var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}
const round2 = (v) => Math.round(v * 100) / 100;

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) throw new Error('Invalid tenantId');

var clientFinalId = data.clientFinalId || null;
if (clientFinalId && !uuidRegex.test(clientFinalId)) clientFinalId = null;

var nom = esc(data.nom || 'Prévisionnel');
var description = esc(data.description || '');
var annee = parseInt(data.annee) || new Date().getFullYear();
var statut = data.statut || 'brouillon';

// Données complètes du prévisionnel
var donnees = data.donnees || {};
var donneesJSON = esc(JSON.stringify(donnees));

// Calculs des résultats dénormalisés
var caAnnuel = 0;
var chargesAnnuelles = 0;

if (donnees.lignesCA && Array.isArray(donnees.lignesCA)) {
  donnees.lignesCA.forEach(function(l) {
    if (l.montantsMensuels && Array.isArray(l.montantsMensuels)) {
      l.montantsMensuels.forEach(function(m) { caAnnuel += Number(m) || 0; });
    }
  });
}
if (donnees.lignesCharges && Array.isArray(donnees.lignesCharges)) {
  donnees.lignesCharges.forEach(function(l) {
    if (l.montantsMensuels && Array.isArray(l.montantsMensuels)) {
      l.montantsMensuels.forEach(function(m) { chargesAnnuelles += Number(m) || 0; });
    }
  });
}

// Amortissements
var amortAnnuel = 0;
if (donnees.investissements && Array.isArray(donnees.investissements)) {
  donnees.investissements.forEach(function(inv) {
    var duree = Number(inv.dureeAmortissement) || 1;
    var moisAcq = Number(inv.moisAcquisition) || 0;
    var mensuel = (Number(inv.montantHT) || 0) / (duree * 12);
    amortAnnuel += mensuel * (12 - moisAcq);
  });
}

var resultatExploitation = round2(caAnnuel - chargesAnnuelles - amortAnnuel);

// Seuil de rentabilité
var chargesFixes = 0;
var chargesVariables = 0;
if (donnees.lignesCharges && Array.isArray(donnees.lignesCharges)) {
  donnees.lignesCharges.forEach(function(l) {
    var total = 0;
    if (l.montantsMensuels) l.montantsMensuels.forEach(function(m) { total += Number(m) || 0; });
    if (l.categorie === 'variable') chargesVariables += total;
    else chargesFixes += total;
  });
}
var tauxMarge = caAnnuel > 0 ? (caAnnuel - chargesVariables) / caAnnuel : 0;
var seuilRentabilite = tauxMarge > 0 ? round2(chargesFixes / tauxMarge) : 0;

// Trésorerie finale
var tresorerieFinale = 0;
if (donnees.financements && Array.isArray(donnees.financements)) {
  donnees.financements.forEach(function(f) { tresorerieFinale += Number(f.montant) || 0; });
}
if (donnees.investissements && Array.isArray(donnees.investissements)) {
  donnees.investissements.forEach(function(inv) {
    tresorerieFinale -= (Number(inv.montantHT) || 0) * (1 + (Number(inv.tva) || 0) / 100);
  });
}
tresorerieFinale += caAnnuel * 1.2 - chargesAnnuelles * 1.12;
tresorerieFinale = round2(tresorerieFinale);

var id = require('crypto').randomUUID();
var now = new Date().toISOString();

var query = "INSERT INTO previsionnels (id, tenant_id, client_final_id, nom, description, annee, statut, donnees, ca_annuel, charges_annuelles, resultat_exploitation, seuil_rentabilite, tresorerie_finale, created_at, updated_at) VALUES ('" + esc(id) + "', '" + esc(tenantId) + "', " + (clientFinalId ? "'" + esc(clientFinalId) + "'" : "NULL") + ", '" + nom + "', '" + description + "', " + annee + ", '" + esc(statut) + "', '" + donneesJSON + "'::jsonb, " + round2(caAnnuel) + ", " + round2(chargesAnnuelles) + ", " + resultatExploitation + ", " + seuilRentabilite + ", " + tresorerieFinale + ", '" + esc(now) + "', '" + esc(now) + "') RETURNING *;";

return [{json: {query: query}}];

var row = $input.first().json;
if (!row || !row.id) {
  return [{json: {success: false, error: 'Création échouée'}}];
}

var donnees = {};
try {
  donnees = typeof row.donnees === 'string' ? JSON.parse(row.donnees) : (row.donnees || {});
} catch(e) { donnees = {}; }

return [{json: {
  success: true,
  data: {
    id: row.id,
    tenantId: row.tenant_id,
    clientFinalId: row.client_final_id || null,
    nom: row.nom,
    description: row.description || null,
    annee: Number(row.annee),
    statut: row.statut,
    donnees: donnees,
    caAnnuel: Number(row.ca_annuel || 0),
    chargesAnnuelles: Number(row.charges_annuelles || 0),
    resultatExploitation: Number(row.resultat_exploitation || 0),
    seuilRentabilite: Number(row.seuil_rentabilite || 0),
    tresorerieFinale: Number(row.tresorerie_finale || 0),
    createdAt: row.created_at,
    updatedAt: row.updated_at
  }
}}];
